PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?dynasty ?dynastyLabel ?predecessor ?predecessorLabel WHERE {
  ?dynasty wdt:P31 wd:Q23240358 ; wdt:P177 wd:Q142 ; wdt:P2102 ?predecessor .
  OPTIONAL {
    ?dynasty rdfs:label ?dynastyLabel .
    FILTER(LANG(?dynastyLabel) = 'en')
  }
  OPTIONAL {
    ?predecessor rdfs:label ?predecessorLabel .
    FILTER(LANG(?predecessorLabel) = 'en')
  }
}
LIMIT 10

